#pragma once\\\\\n#include <cstdint>\\\\n#include <cstddef>\\\\n\\\\n// Naive implementation with proper loops, no intrinsics, and fully matching interface\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\n    for (size_t i = 0; i < M; ++i) {\\n        for (size_t j = 0; j < K; ++j) {\\n            float abSum = 0.0f;\\n            for (size_t p = 0; p < K; ++p) {\\n                // Extract sign for B[p][j] from packed 32-bit integer\n                uint32_t b = B[p * (K/32) + j/32];\\n                float sign = (b & (1u << (j % 32))) ? 1.0f : -1.0f;\\n                abSum += A[i * K + p] * sign;\\n            }\\n            C[i * K + j] = abSum;\\n        }\n    }\\n}